// Extract safe metadata — never retain raw exception messages, stack traces, or capture text
const payload = $input.first().json;

const workflowName = payload?.workflow?.name ?? null;
const workflowId = payload?.workflow?.id ?? null;
const executionId = payload?.execution?.id ?? null;
const lastNode = payload?.execution?.lastNodeExecuted ?? null;
// Error name (type category) is safe; raw message and stack are not retained
const errorCategory = payload?.execution?.error?.name ?? null;

return [{
  json: {
    workflow_name: workflowName,
    workflow_id: workflowId,
    execution_id: executionId,
    last_node: lastNode,
    safe_error_category: errorCategory,
    timestamp: new Date().toISOString(),
  }
}];
